-- ============================================
-- Legislacao full-site: garotinho / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/160539
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = garotinho-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 200 rows Camara legacy existentes, somente 41
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=160539, tipo Deputado(a), ordemAssinatura=1.
-- 159 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'garotinho';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'garotinho: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 200 THEN
    RAISE EXCEPTION 'Pre-condicao garotinho: esperadas 200 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('613533', '615053', '597088', '590422', '585092', '786898', '777577', '619791', '614023', '597083', '586772', '619790', '597081', '593603', '618237', '613419', '617427', '613417', '604213', '593224', '615623', '613415', '615246', '612986', '600108', '614508', '597748', '597084', '597107', '597113', '599523', '597086', '597105', '596550', '593225', '588226', '590421', '591763', '588227', '585314', '585313');
  IF target_present <> 41 THEN
    RAISE EXCEPTION 'Pre-condicao garotinho: esperadas 41 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('613533', '615053', '597088', '590422', '585092', '786898', '777577', '619791', '614023', '597083', '586772', '619790', '597081', '593603', '618237', '613419', '617427', '613417', '604213', '593224', '615623', '613415', '615246', '612986', '600108', '614508', '597748', '597084', '597107', '597113', '599523', '597086', '597105', '596550', '593225', '588226', '590421', '591763', '588227', '585314', '585313')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'garotinho-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao garotinho: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao garotinho: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

